/**
 * Analytics service — aggregates order and user data into dashboard metrics.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture notes:
 * - This service is read-only; it does not modify data or emit events.
 * - All aggregation logic lives here, not in repositories.
 * - Methods return pre-computed summaries; callers should not need to
 *   post-process the results.
 * - The service follows the same dependency injection pattern as other
 *   services (constructor params, no direct imports of singletons).
 */

import type { Order } from '../models/order.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeGranularity,
  TimeSeriesPoint,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get the full dashboard data for a given query.
   */
  getDashboard(query: AnalyticsQuery): DashboardData {
    this.logger.info(
      `Generating dashboard: ${query.startDate.toISOString()} to ${query.endDate.toISOString()}`,
    );

    const summaries = this.getAllMetricSummaries(query);
    const ordersByStatus = this.getOrderStatusBreakdown(query);

    return {
      summaries,
      ordersByStatus,
      generatedAt: new Date(),
      query,
    };
  }

  /**
   * Get a summary for a single metric type.
   */
  getMetricSummary(metric: MetricType, query: AnalyticsQuery): MetricSummary {
    this.logger.info(`Computing metric: ${metric}`);

    const currentOrders = this.getOrdersInRange(query.startDate, query.endDate, query.userId);
    const { start: prevStart, end: prevEnd } = this.getPreviousPeriod(query.startDate, query.endDate);
    const previousOrders = this.getOrdersInRange(prevStart, prevEnd, query.userId);

    const currentValue = this.computeMetricValue(metric, currentOrders);
    const previousValue = this.computeMetricValue(metric, previousOrders);
    const changePercent = previousValue === 0 ? 0 : ((currentValue - previousValue) / previousValue) * 100;
    const trend = changePercent > 0 ? 'up' : changePercent < 0 ? 'down' : 'flat' as const;

    const timeSeries = this.getTimeSeries(metric, query);

    return {
      metric,
      currentValue,
      previousValue,
      changePercent,
      trend,
      timeSeries,
    };
  }

  /**
   * Get time-series data for a specific metric.
   */
  getTimeSeries(metric: MetricType, query: AnalyticsQuery): TimeSeriesPoint[] {
    this.logger.info(
      `Computing time series for ${metric}, granularity: ${query.granularity}`,
    );

    const buckets = this.generateBuckets(query.startDate, query.endDate, query.granularity);
    const orders = this.getOrdersInRange(query.startDate, query.endDate, query.userId);

    return buckets.map(({ start, end, label }) => {
      const bucketOrders = orders.filter(
        (o) => o.createdAt >= start && o.createdAt < end,
      );
      return {
        timestamp: start,
        value: this.computeMetricValue(metric, bucketOrders),
        label,
      };
    });
  }

  /**
   * Get breakdown of orders by status within the query period.
   */
  getOrderStatusBreakdown(query: AnalyticsQuery): OrderStatusBreakdown[] {
    this.logger.info('Computing order status breakdown');

    const orders = this.getOrdersInRange(query.startDate, query.endDate, query.userId);
    if (orders.length === 0) {
      return [];
    }

    const counts = new Map<string, number>();
    for (const order of orders) {
      counts.set(order.status, (counts.get(order.status) ?? 0) + 1);
    }

    const total = orders.length;
    const breakdown: OrderStatusBreakdown[] = [];
    for (const [status, count] of counts) {
      breakdown.push({
        status,
        count,
        percent: (count / total) * 100,
      });
    }

    return breakdown;
  }

  /**
   * Compute summaries for all supported metric types.
   */
  private getAllMetricSummaries(query: AnalyticsQuery): MetricSummary[] {
    const metricTypes: MetricType[] = [
      'total-orders',
      'total-revenue',
      'active-users',
      'order-completion-rate',
    ];

    return metricTypes.map((metric) => this.getMetricSummary(metric, query));
  }

  /**
   * Fetch orders within a date range, optionally filtered by userId.
   */
  private getOrdersInRange(startDate: Date, endDate: Date, userId?: string): Order[] {
    return this.orderRepository.findAll((order) => {
      if (order.createdAt < startDate || order.createdAt > endDate) {
        return false;
      }
      if (userId && order.userId !== userId) {
        return false;
      }
      return true;
    });
  }

  /**
   * Compute a previous period of equal duration shifted backwards.
   */
  private getPreviousPeriod(startDate: Date, endDate: Date): { start: Date; end: Date } {
    const durationMs = endDate.getTime() - startDate.getTime();
    return {
      start: new Date(startDate.getTime() - durationMs),
      end: new Date(endDate.getTime() - durationMs),
    };
  }

  /**
   * Compute the value of a metric from a set of orders.
   */
  private computeMetricValue(metric: MetricType, orders: Order[]): number {
    switch (metric) {
      case 'total-orders':
        return orders.length;
      case 'total-revenue':
        return orders.reduce((sum, o) => sum + o.total, 0);
      case 'active-users':
        return new Set(orders.map((o) => o.userId)).size;
      case 'order-completion-rate':
        if (orders.length === 0) return 0;
        return (orders.filter((o) => o.status === 'delivered').length / orders.length) * 100;
    }
  }

  /**
   * Generate time buckets from startDate to endDate based on granularity.
   */
  private generateBuckets(
    startDate: Date,
    endDate: Date,
    granularity: TimeGranularity,
  ): Array<{ start: Date; end: Date; label: string }> {
    const buckets: Array<{ start: Date; end: Date; label: string }> = [];
    let current = new Date(startDate);

    while (current < endDate) {
      const next = this.advanceByGranularity(current, granularity);
      const bucketEnd = next > endDate ? endDate : next;
      buckets.push({
        start: new Date(current),
        end: bucketEnd,
        label: this.formatBucketLabel(current, granularity),
      });
      current = next;
    }

    return buckets;
  }

  /**
   * Advance a date by one granularity unit.
   */
  private advanceByGranularity(date: Date, granularity: TimeGranularity): Date {
    const result = new Date(date);
    switch (granularity) {
      case 'hour':
        result.setHours(result.getHours() + 1);
        break;
      case 'day':
        result.setDate(result.getDate() + 1);
        break;
      case 'week':
        result.setDate(result.getDate() + 7);
        break;
      case 'month':
        result.setMonth(result.getMonth() + 1);
        break;
    }
    return result;
  }

  /**
   * Format a human-readable label for a time bucket.
   */
  private formatBucketLabel(date: Date, granularity: TimeGranularity): string {
    const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

    switch (granularity) {
      case 'hour':
        return `${String(date.getHours()).padStart(2, '0')}:00`;
      case 'day':
        return `${monthNames[date.getMonth()]} ${date.getDate()}`;
      case 'week': {
        const weekNum = Math.ceil(date.getDate() / 7);
        return `Week ${weekNum}`;
      }
      case 'month':
        return monthNames[date.getMonth()];
    }
  }
}

